```c
#define FRAME_START 0x7E
#define FRAME_END   0x7E
#define FRAME_ESC   0x7D
#define ESC_XOR     0x20

size_t frame_encode(const uint8_t *data, size_t len, uint8_t *out) {
    size_t pos = 0;
    out[pos++] = FRAME_START;
    for (size_t i = 0; i < len; i++) {
        if (data[i] == FRAME_START || data[i] == FRAME_ESC) {
            out[pos++] = FRAME_ESC;
            out[pos++] = data[i] ^ ESC_XOR;
        } else {
            out[pos++] = data[i];
        }
    }
    out[pos++] = FRAME_END;
    return pos;
}
```

**Byte stuffing:** When the data contains a delimiter byte (0x7E), replace it with ESC + (byte XOR 0x20). The receiver reverses this. Ensures delimiters are unambiguous.

