```c
#include <pthread.h>
#include <string.h>
#include <stdbool.h>

typedef struct {
    void        **buf;
    size_t       capacity;
    size_t       head;
    size_t       tail;
    size_t       count;
    pthread_mutex_t lock;
    pthread_cond_t  not_empty;
    pthread_cond_t  not_full;
    bool         closed; // For graceful shutdown
} BlockingQueue;

int bq_init(BlockingQueue *q, size_t capacity) {
    q->buf = calloc(capacity, sizeof(void *));
    if (!q->buf) return -1;
    q->capacity = capacity;
    q->head = q->tail = q->count = 0;
    q->closed = false;
    pthread_mutex_init(&q->lock, NULL);
    pthread_cond_init(&q->not_empty, NULL);
    pthread_cond_init(&q->not_full, NULL);
    return 0;
}

// Returns false if queue is closed
bool bq_push(BlockingQueue *q, void *item) {
    pthread_mutex_lock(&q->lock);
    // Wait while full (must be while loop — spurious wakeups!)
    while (q->count == q->capacity && !q->closed)
        pthread_cond_wait(&q->not_full, &q->lock);
    if (q->closed) {
        pthread_mutex_unlock(&q->lock);
        return false;
    }
    q->buf[q->tail] = item;
    q->tail = (q->tail + 1) % q->capacity;
    q->count++;
    pthread_cond_signal(&q->not_empty);
    pthread_mutex_unlock(&q->lock);
    return true;
}

// Returns NULL if queue is closed and empty
void *bq_pop(BlockingQueue *q) {
    pthread_mutex_lock(&q->lock);
    // Wait while empty
    while (q->count == 0 && !q->closed)
        pthread_cond_wait(&q->not_empty, &q->lock);
    if (q->count == 0) { // Closed and empty
        pthread_mutex_unlock(&q->lock);
        return NULL;
    }
    void *item = q->buf[q->head];
    q->head = (q->head + 1) % q->capacity;
    q->count--;
    pthread_cond_signal(&q->not_full);
    pthread_mutex_unlock(&q->lock);
    return item;
}

void bq_close(BlockingQueue *q) {
    pthread_mutex_lock(&q->lock);
    q->closed = true;
    pthread_cond_broadcast(&q->not_empty); // Wake blocked consumers
    pthread_cond_broadcast(&q->not_full);  // Wake blocked producers
    pthread_mutex_unlock(&q->lock);
}
```

**Critical design decisions:**
1. **`while` loop on condition variables** — never `if`. Spurious wakeups are real; another consumer can drain the queue between signal and this thread's wakeup.
2. **Two condition variables** — `not_empty` for consumers waiting, `not_full` for producers waiting. Using one CV with `broadcast` works but is less efficient.
3. **`closed` flag** — needed for graceful shutdown. Without it, consumers block forever after the producer exits.
4. **`signal` vs `broadcast`** — signal when adding one item wakes one consumer. Broadcast used on close to wake all blocked threads.

**Display pipeline use:**
```
Compositor (producer) → [BlockingQueue<Frame*>] → Display Driver (consumer)
                          capacity = 2-3 frames
```
The driver blocks until a frame is ready. The compositor blocks if it's rendering too far ahead.

