```cpp
#include <cstdint>
#include <utility>

// Simulated HAL — replace with actual MCU HAL
namespace hal {
    void gpio_init_output(uint32_t pin, bool initial_state);
    void gpio_set(uint32_t pin, bool state);
    void gpio_deinit(uint32_t pin);  // Reset to high-Z input
}

class GpioOutput {
public:
    // Constructor: claims and configures the pin
    explicit GpioOutput(uint32_t pin, bool initial_state = false)
        : pin_(pin), owned_(true)
    {
        hal::gpio_init_output(pin_, initial_state);
    }

    // Destructor: releases the pin (safe input state)
    ~GpioOutput() {
        if (owned_) {
            hal::gpio_set(pin_, false);   // Drive low before releasing
            hal::gpio_deinit(pin_);       // High-Z input — safe default
        }
    }

    // Non-copyable — two objects can't own the same pin
    GpioOutput(const GpioOutput&) = delete;
    GpioOutput& operator=(const GpioOutput&) = delete;

    // Move-constructible — transfer ownership
    GpioOutput(GpioOutput&& other) noexcept
        : pin_(other.pin_), owned_(other.owned_)
    {
        other.owned_ = false;  // Source no longer owns the pin
    }

    // Move-assignable
    GpioOutput& operator=(GpioOutput&& other) noexcept {
        if (this != &other) {
            if (owned_) {
                hal::gpio_set(pin_, false);
                hal::gpio_deinit(pin_);
            }
            pin_ = other.pin_;
            owned_ = other.owned_;
            other.owned_ = false;
        }
        return *this;
    }

    void set(bool state) { if (owned_) hal::gpio_set(pin_, state); }
    void high()          { set(true); }
    void low()           { set(false); }
    uint32_t pin() const { return pin_; }

private:
    uint32_t pin_;
    bool     owned_;
};
```

**Why RAII is powerful here:**
- Error paths, early returns, and exceptions all correctly release the pin
- No `goto cleanup` or duplicated `gpio_deinit()` calls
- The type system enforces ownership: if you have a `GpioOutput`, you own the pin
- Move semantics allow storing `GpioOutput` in containers or returning from factory functions

**Common embedded RAII patterns:**
- `MutexLock` / `CriticalSection` — acquire on construction, release on destruction
- `DmaHandle` — configure DMA on construction, disable/free on destruction
- `PowerDomain` — enable regulator on construction, disable when last reference gone
- `I2cBus` — lock bus on construction (for multi-master), release on destruction

