```cpp
#include <cstdint>
#include <type_traits>
#include <new>

// Minimal Result<T, E> — holds either success value or error
template<typename T, typename E>
class Result {
public:
    static Result ok(T val)  { Result r; r.has_val_ = true;  new(&r.val_) T(val);  return r; }
    static Result err(E err) { Result r; r.has_val_ = false; new(&r.err_) E(err); return r; }

    ~Result() {
        if (has_val_) reinterpret_cast<T*>(&val_)->~T();
        else          reinterpret_cast<E*>(&err_)->~E();
    }

    explicit operator bool() const { return has_val_; }
    bool has_value() const { return has_val_; }

    T& value() { return *reinterpret_cast<T*>(&val_); }
    E& error() { return *reinterpret_cast<E*>(&err_); }

private:
    bool has_val_{false};
    alignas(T) alignas(E) union {
        typename std::aligned_storage<sizeof(T), alignof(T)>::type val_;
        typename std::aligned_storage<sizeof(E), alignof(E)>::type err_;
    };
    Result() = default;
};

// Application layer
enum class I2cErr { Timeout, Nack, BusError };

Result<uint8_t, I2cErr> i2c_read_byte(uint8_t dev, uint8_t reg) {
    if (!i2c_start(dev, I2C_WRITE))  return Result<uint8_t,I2cErr>::err(I2cErr::Nack);
    if (!i2c_write_byte(reg))        return Result<uint8_t,I2cErr>::err(I2cErr::Timeout);
    if (!i2c_restart(dev, I2C_READ)) return Result<uint8_t,I2cErr>::err(I2cErr::Nack);
    uint8_t val = i2c_read_ack(false);
    i2c_stop();
    return Result<uint8_t, I2cErr>::ok(val);
}

Result<uint16_t, I2cErr> read_reg16(uint8_t dev, uint8_t reg) {
    auto hi = i2c_read_byte(dev, reg);
    if (!hi) return Result<uint16_t,I2cErr>::err(hi.error());

    auto lo = i2c_read_byte(dev, reg + 1);
    if (!lo) return Result<uint16_t,I2cErr>::err(lo.error());

    uint16_t val = (static_cast<uint16_t>(hi.value()) << 8) | lo.value();
    return Result<uint16_t, I2cErr>::ok(val);
}

void sensor_task() {
    auto result = read_reg16(0x48, 0x00);
    if (!result) {
        log_error("Sensor read failed: %d", (int)result.error());
        return;
    }
    float temp = result.value() * 0.0078125f;  // TMP117 LSB = 7.8125 mdegC
    update_display(temp);
}
```

**Comparison of error handling strategies:**

| Strategy | Pros | Cons |
|---|---|---|
| `int` return code | Simple, universal | Easy to ignore, no value + error together |
| Output parameters | Returns both value and error | Awkward, not composable |
| `Result<T,E>` | Type-safe, composable, self-documenting | More verbose |
| Exceptions | Automatic propagation | Heap, code size, non-deterministic — banned in embedded |

**C++23 `std::expected`** is now standard and provides the same pattern with `.and_then()`, `.or_else()`, and `.transform()` monadic combinators. Most embedded projects targeting C++17 use `tl::expected` (header-only, C++11 compatible).

