#include <cstdio>

// --- Base with virtual ---
class Base {
public:
    virtual void speak() { printf("Base::speak()\n"); }
    virtual ~Base() { printf("Base destroyed\n"); }
};

class Derived : public Base {
public:
    Derived() { printf("Derived constructed\n"); }
    void speak() override { printf("Derived::speak()\n"); }
    ~Derived() override { printf("Derived destroyed\n"); }
};

// --- Base WITHOUT virtual destructor ---
class BadBase {
public:
    virtual void speak() { printf("BadBase::speak()\n"); }
    ~BadBase() { printf("Base destroyed only!\n"); }  // NOT virtual!
};

class BadDerived : public BadBase {
    int* leak;
public:
    BadDerived() : leak(new int[100]) {}
    void speak() override { printf("BadDerived::speak()\n"); }
    ~BadDerived() { delete[] leak; printf("BadDerived destroyed\n"); }
};

int main() {
    printf("--- Section 1: Virtual dispatch ---\n");
    Derived d;
    Base* bp = &d;
    bp->speak();       // What prints?
    Base b;
    b.speak();         // What prints?

    printf("\n--- Section 2: Object slicing ---\n");
    Base b2 = d;       // What happens here?
    b2.speak();        // What prints?

    printf("\n--- Section 3: Destructor behavior ---\n");
    {
        Base* bp2 = new Derived();
        delete bp2;    // What gets destroyed?
    }

    printf("\n--- Section 4: No virtual destructor ---\n");
    {
        BadBase* bp3 = new BadDerived();
        delete bp3;    // What gets destroyed?
    }

    // Note: remaining destructors fire here for d, b, b2
    printf("\n--- Cleanup ---\n");
    return 0;
}

