```cpp
#include <cstdio>
#include <cstdint>
#include <cstring>

class IComm {
public:
    virtual bool init(uint32_t config) = 0;
    virtual int send(const uint8_t* data, size_t len) = 0;
    virtual int receive(uint8_t* buf, size_t maxLen) = 0;
    virtual void deinit() = 0;
    virtual const char* name() const = 0;
    virtual ~IComm() = default;
};

class UartDriver : public IComm {
    uint32_t baudRate = 0;
    bool initialized = false;
public:
    bool init(uint32_t config) override {
        baudRate = config;
        initialized = true;
        printf("[UART] Init at %u baud\n", baudRate);
        return true;
    }
    int send(const uint8_t* data, size_t len) override {
        if (!initialized) return -1;
        printf("[UART] TX %zu bytes\n", len);
        return (int)len;
    }
    int receive(uint8_t* buf, size_t maxLen) override {
        if (!initialized) return -1;
        const char* fake = "UART_OK";
        size_t n = strlen(fake);
        if (n > maxLen) n = maxLen;
        memcpy(buf, fake, n);
        printf("[UART] RX %zu bytes\n", n);
        return (int)n;
    }
    void deinit() override {
        initialized = false;
        printf("[UART] Deinit\n");
    }
    const char* name() const override { return "UART"; }
};

class SpiDriver : public IComm {
    uint32_t clockHz = 0;
    bool initialized = false;
public:
    bool init(uint32_t config) override {
        clockHz = config;
        initialized = true;
        printf("[SPI] Init at %u Hz\n", clockHz);
        return true;
    }
    int send(const uint8_t* data, size_t len) override {
        if (!initialized) return -1;
        printf("[SPI] TX %zu bytes\n", len);
        return (int)len;
    }
    int receive(uint8_t* buf, size_t maxLen) override {
        if (!initialized) return -1;
        const char* fake = "SPI_OK";
        size_t n = strlen(fake);
        if (n > maxLen) n = maxLen;
        memcpy(buf, fake, n);
        printf("[SPI] RX %zu bytes\n", n);
        return (int)n;
    }
    void deinit() override {
        initialized = false;
        printf("[SPI] Deinit\n");
    }
    const char* name() const override { return "SPI"; }
};

void runDiagnostics(IComm* driver) {
    printf("\n=== Diagnostics: %s ===\n", driver->name());
    driver->init(115200);
    uint8_t tx[] = {0xDE, 0xAD};
    driver->send(tx, sizeof(tx));
    uint8_t rx[32];
    int n = driver->receive(rx, sizeof(rx));
    if (n > 0) printf("  Received: %.*s\n", n, rx);
    driver->deinit();
}

int main() {
    UartDriver uart;
    SpiDriver spi;
    runDiagnostics(&uart);
    runDiagnostics(&spi);
    printf("\nAll diagnostics complete.\n");
    return 0;
}
```

**Key points:**
- `IComm` is a pure abstract class (interface) — cannot be instantiated
- `virtual ~IComm() = default` ensures proper cleanup through base pointers
- `runDiagnostics` works with ANY `IComm` implementation — open/closed principle
- `override` keyword catches signature mismatches at compile time
- No dynamic allocation needed — polymorphism works with stack objects via pointers

