#include <stdio.h>
#include <stdbool.h>

#define MAX_HEAP 128

typedef struct { int priority; int data; } HeapItem;

typedef struct {
    HeapItem items[MAX_HEAP];
    int size;
} MinHeap;

void heap_init(MinHeap *h) { h->size = 0; }
bool heap_empty(MinHeap *h) { return h->size == 0; }
bool heap_full(MinHeap *h) { return h->size >= MAX_HEAP; }

static void swap(HeapItem *a, HeapItem *b) {
    HeapItem t = *a; *a = *b; *b = t;
}

bool heap_insert(MinHeap *h, int priority, int data) {
    if (heap_full(h)) return false;
    int i = h->size++;
    h->items[i] = (HeapItem){priority, data};
    // Bubble up
    while (i > 0) {
        int parent = (i - 1) / 2;
        if (h->items[i].priority < h->items[parent].priority) {
            swap(&h->items[i], &h->items[parent]);
            i = parent;
        } else break;
    }
    return true;
}

bool heap_extract_min(MinHeap *h, HeapItem *out) {
    if (heap_empty(h)) return false;
    *out = h->items[0];
    h->items[0] = h->items[--h->size];
    // Bubble down
    int i = 0;
    while (1) {
        int left = 2*i + 1, right = 2*i + 2, smallest = i;
        if (left < h->size && h->items[left].priority < h->items[smallest].priority)
            smallest = left;
        if (right < h->size && h->items[right].priority < h->items[smallest].priority)
            smallest = right;
        if (smallest == i) break;
        swap(&h->items[i], &h->items[smallest]);
        i = smallest;
    }
    return true;
}
```

**Complexity:** Insert O(log n), Extract O(log n), Peek O(1).

**Firmware uses:**
- RTOS scheduler: tasks sorted by priority, O(log n) to find next task
- Timer wheel: earliest-expiring timer at the top
- Event queue: highest-priority event processed first
- Dijkstra's algorithm in network routing firmware

**Why array-based (no malloc):** Embedded systems often forbid dynamic allocation after init. Fixed array = deterministic memory, no fragmentation, cache-friendly.

