#include <stdio.h>
#include <stdbool.h>
#include <string.h>

#define TABLE_SIZE 16  // Power of 2 for fast modulo
#define EMPTY    0
#define DELETED  1
#define OCCUPIED 2

typedef struct {
    int key;
    int value;
    int state;  // EMPTY, DELETED, or OCCUPIED
} Entry;

typedef struct {
    Entry entries[TABLE_SIZE];
    int count;
} HashTable;

void ht_init(HashTable *t) {
    memset(t, 0, sizeof(*t));
}

static int hash(int key) {
    return ((unsigned)key * 2654435761u) >> 16 & (TABLE_SIZE - 1);
}

bool ht_insert(HashTable *t, int key, int value) {
    if (t->count >= TABLE_SIZE * 3 / 4) return false; // Load factor limit
    int idx = hash(key);
    int first_deleted = -1;
    for (int i = 0; i < TABLE_SIZE; i++) {
        int probe = (idx + i) & (TABLE_SIZE - 1);
        if (t->entries[probe].state == EMPTY) {
            int slot = (first_deleted >= 0) ? first_deleted : probe;
            t->entries[slot] = (Entry){key, value, OCCUPIED};
            t->count++;
            return true;
        }
        if (t->entries[probe].state == DELETED && first_deleted < 0)
            first_deleted = probe;
        if (t->entries[probe].state == OCCUPIED && t->entries[probe].key == key) {
            t->entries[probe].value = value; // Update
            return true;
        }
    }
    return false;
}

bool ht_get(HashTable *t, int key, int *value) {
    int idx = hash(key);
    for (int i = 0; i < TABLE_SIZE; i++) {
        int probe = (idx + i) & (TABLE_SIZE - 1);
        if (t->entries[probe].state == EMPTY) return false;
        if (t->entries[probe].state == OCCUPIED && t->entries[probe].key == key) {
            *value = t->entries[probe].value;
            return true;
        }
    }
    return false;
}

bool ht_delete(HashTable *t, int key) {
    int idx = hash(key);
    for (int i = 0; i < TABLE_SIZE; i++) {
        int probe = (idx + i) & (TABLE_SIZE - 1);
        if (t->entries[probe].state == EMPTY) return false;
        if (t->entries[probe].state == OCCUPIED && t->entries[probe].key == key) {
            t->entries[probe].state = DELETED; // Tombstone!
            t->count--;
            return true;
        }
    }
    return false;
}
```

**Why tombstones (DELETED state)?**
With linear probing, if you just mark a slot as EMPTY on delete, you break the probe chain. Later lookups for keys that probed past that slot will stop too early and falsely report 'not found'. Tombstones keep the chain intact while allowing the slot to be reused by future inserts.

**Firmware context:**
- Command dispatch tables (command ID → handler function pointer)
- Device registry (address → device struct)
- Symbol tables in bootloader/debugger
- Protocol session tracking (connection ID → state)

**Why open addressing over chaining in firmware:**
- No malloc/free needed (all in one contiguous array)
- Better cache performance (sequential memory access during probing)
- Predictable memory usage (fixed table size, no linked-list overhead)

