#include <cstdio>
#include <cstring>
#include <cstdint>

#define MAX_CMD_LEN 16

typedef struct {
    char buffer[MAX_CMD_LEN];
    int length;
} command_t;

int parse_command(const char* input, command_t* cmd) {
    int len = strlen(input);

    if (len > MAX_CMD_LEN) {
        printf("Command too long\n");
        return -1;
    }

    strcpy(cmd->buffer, input);
    cmd->length = len;
    return 0;
}

int main() {
    command_t cmd;

    // These should work fine
    parse_command("LED ON", &cmd);
    printf("Parsed: '%s' (len=%d)\n", cmd.buffer, cmd.length);

    parse_command("TEMP READ", &cmd);
    printf("Parsed: '%s' (len=%d)\n", cmd.buffer, cmd.length);

    // This is exactly MAX_CMD_LEN characters - does it work?
    parse_command("CALIBRATE SENSOR", &cmd);  // 16 chars!
    printf("Parsed: '%s' (len=%d)\n", cmd.buffer, cmd.length);

    printf("Done\n");
    return 0;
}

questions.answer:
**Bug: `>` should be `>=`** (or better: `> MAX_CMD_LEN - 1`)

```c
if (len > MAX_CMD_LEN)  // allows len == 16
```

When `len == 16` (exactly `MAX_CMD_LEN`), the check passes. But `strcpy` copies 16 chars **plus a null terminator** = 17 bytes into a 16-byte buffer. That's a one-byte overflow that corrupts `cmd->length` (or whatever follows `buffer` in memory).

**Fix:**
```c
if (len >= MAX_CMD_LEN) {  // now rejects len == 16
    printf("Command too long\n");
    return -1;
}
```

**Or use `strncpy` for defense in depth:**
```c
if (len >= MAX_CMD_LEN) return -1;
strncpy(cmd->buffer, input, MAX_CMD_LEN - 1);
cmd->buffer[MAX_CMD_LEN - 1] = '\0';
```

**Why this is insidious:** The overflow is exactly 1 byte — the null terminator. On most architectures it corrupts `length` (the next struct member). With different struct packing or alignment it might corrupt padding bytes and appear to work. Classic "works on my machine" bug.

**The deeper lesson:** Any time you see `strlen() > BUFSIZE` guarding a `strcpy`, it's almost certainly wrong. The null terminator is the perennial +1 that gets forgotten.

