#include <cstdio>
#include <cstdint>
#include <cstring>
#include <pthread.h>

typedef struct {
    pthread_mutex_t lock;
    uint8_t data[256];
    int count;
    const char* name;
} buffer_t;

buffer_t buf_a = { PTHREAD_MUTEX_INITIALIZER, {0}, 0, "A" };
buffer_t buf_b = { PTHREAD_MUTEX_INITIALIZER, {0}, 0, "B" };

// Transfer from src to dst
void transfer(buffer_t* src, buffer_t* dst) {
    pthread_mutex_lock(&src->lock);
    printf("  Locked %s\n", src->name);

    // Simulate some work
    for (volatile int i = 0; i < 1000; i++) {}

    pthread_mutex_lock(&dst->lock);
    printf("  Locked %s\n", dst->name);

    if (src->count > 0) {
        int n = src->count < 10 ? src->count : 10;
        memcpy(dst->data + dst->count, src->data, n);
        dst->count += n;
        src->count -= n;
        printf("  Transferred %d bytes %s -> %s\n", n, src->name, dst->name);
    }

    pthread_mutex_unlock(&dst->lock);
    pthread_mutex_unlock(&src->lock);
}

// Thread 1: moves data A -> B
void* thread1(void* arg) {
    for (int i = 0; i < 100; i++) {
        printf("T1: A -> B\n");
        transfer(&buf_a, &buf_b);
    }
    return NULL;
}

// Thread 2: moves data B -> A
void* thread2(void* arg) {
    for (int i = 0; i < 100; i++) {
        printf("T2: B -> A\n");
        transfer(&buf_b, &buf_a);
    }
    return NULL;
}

int main() {
    buf_a.count = 50;
    buf_b.count = 50;

    pthread_t t1, t2;
    pthread_create(&t1, NULL, thread1, NULL);
    pthread_create(&t2, NULL, thread2, NULL);

    pthread_join(t1, NULL);
    pthread_join(t2, NULL);

    printf("Final: A=%d B=%d\n", buf_a.count, buf_b.count);
    printf("Done\n");
    return 0;
}

questions.answer:
**Bug: Classic ABBA deadlock.**

Thread 1 calls `transfer(&buf_a, &buf_b)` → locks A then B.
Thread 2 calls `transfer(&buf_b, &buf_a)` → locks B then A.

If both threads lock their first mutex simultaneously:
```
T1: holds A, waiting for B
T2: holds B, waiting for A
→ DEADLOCK
```

**Fix: Enforce a consistent lock ordering.** Always lock the "lower" address (or lower ID) first, regardless of transfer direction:

```c
void transfer(buffer_t* src, buffer_t* dst) {
    // Always lock in consistent order (by address)
    buffer_t* first  = (src < dst) ? src : dst;
    buffer_t* second = (src < dst) ? dst : src;

    pthread_mutex_lock(&first->lock);
    pthread_mutex_lock(&second->lock);

    // ... transfer logic unchanged ...

    pthread_mutex_unlock(&second->lock);
    pthread_mutex_unlock(&first->lock);
}
```

**Alternative fixes:**
1. **Single lock** — if contention is low, just use one mutex for both buffers
2. **trylock** — `pthread_mutex_trylock` on the second lock, release first if it fails (retry)
3. **Lock hierarchy** — assign numeric levels to each mutex, always acquire in ascending order

**The rule:** When acquiring multiple locks, ALWAYS acquire in the same global order. "Lock ordering" is the #1 deadlock prevention technique.

