#include <cstdio>
#include <cstdint>

typedef struct {
    int16_t temperature;  // in 0.1°C units (-400 to 1250 = -40.0°C to 125.0°C)
    uint16_t humidity;    // in 0.1% units (0 to 1000 = 0% to 100%)
    uint16_t pressure;    // in hPa (300 to 1100)
} sensor_reading_t;

int validate_reading(const sensor_reading_t* r) {
    // Check temperature range: -40.0°C to 125.0°C
    if (r->temperature < -400 || r->temperature > 1250) {
        printf("  Temperature out of range: %d\n", r->temperature);
        return -1;
    }

    // Check humidity: 0% to 100%
    if (r->humidity < 0 || r->humidity > 1000) {
        printf("  Humidity out of range: %u\n", r->humidity);
        return -1;
    }

    // Check pressure: 300 to 1100 hPa
    unsigned int low = 300;
    int offset = -50;  // allow 50 below
    if (r->pressure < (low + offset)) {  // intended: < 250
        printf("  Pressure too low: %u\n", r->pressure);
        return -1;
    }

    printf("  Reading OK: temp=%d hum=%u pres=%u\n",
           r->temperature, r->humidity, r->pressure);
    return 0;
}

int main() {
    sensor_reading_t good = {250, 500, 1013};   // 25.0°C, 50%, 1013 hPa
    sensor_reading_t cold = {-200, 300, 900};    // -20.0°C, 30%, 900 hPa
    sensor_reading_t bad_pressure = {200, 400, 100};  // pressure way too low

    printf("Test 1 (good reading):\n");
    validate_reading(&good);

    printf("Test 2 (cold but valid):\n");
    validate_reading(&cold);

    printf("Test 3 (bad pressure - should FAIL):\n");
    int result = validate_reading(&bad_pressure);
    if (result == 0) {
        printf("  BUG: bad pressure was accepted!\n");
    }

    printf("Done\n");
    return 0;
}

#include <cstdio>
#include <cstdlib>

typedef struct node {
    int data;
    struct node* next;
} node_t;

void push(node_t** head, int val) {
    node_t* n = (node_t*)malloc(sizeof(node_t));
    n->data = val;
    n->next = *head;
    *head = n;
}

// Remove all nodes with matching value
void remove_all(node_t** head, int val) {
    node_t* curr = *head;
    node_t* prev = NULL;

    while (curr != NULL) {
        if (curr->data == val) {
            if (prev == NULL) {
                *head = curr->next;
            } else {
                prev->next = curr->next;
            }
            free(curr);
            curr = curr->next;  // BUG: where is this reading from?
        } else {
            prev = curr;
            curr = curr->next;
        }
    }
}

void print_list(node_t* head) {
    printf("List: ");
    while (head) {
        printf("%d -> ", head->data);
        head = head->next;
    }
    printf("NULL\n");
}

void free_list(node_t* head) {
    while (head) {
        node_t* tmp = head;
        head = head->next;
        free(tmp);
    }
}

int main() {
    node_t* list = NULL;
    push(&list, 1);
    push(&list, 3);
    push(&list, 2);
    push(&list, 3);
    push(&list, 3);
    push(&list, 4);

    printf("Before: ");
    print_list(list);

    remove_all(&list, 3);

    printf("After removing 3s: ");
    print_list(list);

    free_list(list);
    printf("Done\n");
    return 0;
}

questions.answer:
**Bug:** `free(curr)` then `curr = curr->next` reads from freed memory.

After `free(curr)`, the memory at `curr` is released. Accessing `curr->next` is **undefined behavior** — it might work, crash, or return garbage (especially if the allocator reuses the memory immediately).

**Fix: Save `next` before freeing:**
```c
if (curr->data == val) {
    node_t* tmp = curr;          // save pointer
    if (prev == NULL) {
        *head = curr->next;
    } else {
        prev->next = curr->next;
    }
    curr = curr->next;           // advance BEFORE freeing
    free(tmp);                   // now safe to free
} else {
```

**Why it "works" sometimes:** Most allocators don't immediately zero freed memory. The `next` pointer is still physically present in the freed block — it just isn't valid anymore. With AddressSanitizer (`-fsanitize=address`) or Valgrind, this lights up immediately.

**In embedded without an OS:** This is even more dangerous. A bare-metal allocator might immediately reuse the block for the next ISR allocation, corrupting the list traversal silently.

