#include <cstdio>
#include <cstdint>

// Simulated hardware register (in real code: volatile uint32_t* at MMIO address)
static volatile uint32_t GPIO_OUT = 0x00000000;

// Read current state for verification
uint32_t gpio_read(void) {
    return GPIO_OUT;
}

void gpio_set_pin(int pin) {
    // Read-modify-write
    uint32_t val = GPIO_OUT;    // READ
    val |= (1U << pin);         // MODIFY
    GPIO_OUT = val;              // WRITE
}

void gpio_clear_pin(int pin) {
    uint32_t val = GPIO_OUT;
    val &= ~(1U << pin);
    GPIO_OUT = val;
}

// Called from main code
void enable_led(void) {
    printf("Main: enabling LED (pin 4)\n");
    gpio_set_pin(4);
}

// Called from timer ISR
void timer_isr_handler(void) {
    // Toggle heartbeat LED on pin 7
    if (GPIO_OUT & (1U << 7)) {
        gpio_clear_pin(7);
    } else {
        gpio_set_pin(7);
    }
}

int main() {
    printf("Initial GPIO: 0x%08X\n", gpio_read());

    // Simulate the race:
    // Main code starts to set pin 4...
    uint32_t val = GPIO_OUT;     // Main reads: 0x00
    val |= (1U << 4);           // Main prepares: 0x10

    // ISR fires RIGHT HERE, between read and write!
    printf("--- ISR fires mid-operation ---\n");
    timer_isr_handler();         // ISR sets pin 7: GPIO = 0x80
    printf("After ISR: GPIO = 0x%08X\n", gpio_read());

    // Main resumes and writes its stale value
    GPIO_OUT = val;              // Main writes: 0x10 (OVERWRITES pin 7!)
    printf("After main resumes: GPIO = 0x%08X\n", gpio_read());

    printf("Pin 4 (LED): %s\n", (GPIO_OUT & (1U << 4)) ? "ON" : "OFF");
    printf("Pin 7 (heartbeat): %s\n", (GPIO_OUT & (1U << 7)) ? "ON" : "OFF");

    // Pin 7 should be ON but got clobbered!
    if (!(GPIO_OUT & (1U << 7))) {
        printf("BUG: Pin 7 was lost in the race!\n");
    }

    printf("Done\n");
    return 0;
}

#include <cstdio>
#include <cstring>

const char* format_status(int code, int temp) {
    char result[64];
    snprintf(result, sizeof(result), "Status: %d, Temp: %d C", code, temp);
    return result;
}

const char* get_error_msg(int code) {
    switch (code) {
        case 0: return "OK";
        case 1: return "TIMEOUT";
        case 2: return "CRC_ERROR";
        default: {
            char msg[32];
            snprintf(msg, sizeof(msg), "UNKNOWN(%d)", code);
            return msg;
        }
    }
}

int main() {
    // Test 1
    const char* status = format_status(0, 25);
    printf("Status: %s\n", status);  // Might print garbage!

    // Test 2 - known codes work fine
    printf("Error 0: %s\n", get_error_msg(0));
    printf("Error 1: %s\n", get_error_msg(1));

    // Test 3 - unknown code: same dangling pointer bug
    const char* err = get_error_msg(99);
    printf("Error 99: %s\n", err);  // Garbage!

    printf("Done\n");
    return 0;
}

questions.answer:
**Bug: Returning pointer to local (stack) variable.**

`result` in `format_status` and `msg` in `get_error_msg`'s default case are local arrays on the stack. When the function returns, the stack frame is reclaimed. The returned pointer is **dangling** — it points to memory that may be overwritten by the next function call.

Note: `get_error_msg` cases 0-2 are fine — string literals have static storage duration.

**Why it sometimes "works":** The stack memory isn't immediately zeroed. If nothing else uses that stack space before `printf`, the data might still be intact. But any function call (including `printf` itself!) can overwrite it.

**Fix options:**

**1. Static buffer (simple, not thread-safe):**
```c
const char* format_status(int code, int temp) {
    static char result[64];  // persists across calls
    snprintf(result, sizeof(result), "Status: %d, Temp: %d C", code, temp);
    return result;
}
```

**2. Caller-provided buffer (best for embedded):**
```c
void format_status(int code, int temp, char* buf, size_t buflen) {
    snprintf(buf, buflen, "Status: %d, Temp: %d C", code, temp);
}
```

**3. Heap allocation (avoid in embedded):**
```c
char* format_status(int code, int temp) {
    char* result = (char*)malloc(64);
    snprintf(result, 64, "Status: %d, Temp: %d C", code, temp);
    return result;  // caller must free()
}
```

**Best practice in firmware:** Option 2. The caller owns the buffer, no hidden state, no allocation, clear lifetime.

