#include <cstdio>
#include <cstdint>

uint8_t compute_crc(uint8_t data[]) {
    uint8_t crc = 0xFF;
    size_t len = sizeof(data);  // How many bytes?

    printf("  Computing CRC over %zu bytes\n", len);
    for (size_t i = 0; i < len; i++) {
        crc ^= data[i];
        for (int j = 0; j < 8; j++) {
            crc = (crc & 0x80) ? ((crc << 1) ^ 0x07) : (crc << 1);
        }
    }
    return crc;
}

void process_packet(uint8_t packet[]) {
    printf("Processing packet of %zu bytes\n", sizeof(packet));
    uint8_t crc = compute_crc(packet);
    printf("Packet CRC: 0x%02X\n", crc);
}

int main() {
    uint8_t data[] = {0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08};

    // Direct computation in main - sizeof works here!
    printf("In main: sizeof(data) = %zu\n", sizeof(data));

    // Through function - sizeof is WRONG
    printf("\nThrough function:\n");
    process_packet(data);

    printf("Done\n");
    return 0;
}

questions.answer:
**Bug: `sizeof(data)` in the function gives the size of a POINTER, not the array.**

When you pass an array to a function, it **decays** to a pointer. The parameter `uint8_t data[]` is identical to `uint8_t* data`. So:

```c
// In main:
sizeof(data)  // = 8 (8 elements × 1 byte) ✓

// In compute_crc:
sizeof(data)  // = 8 on 64-bit, 4 on 32-bit (pointer size!) ✗
```

On a 64-bit system it happens to give 8, which matches the test data length — the bug is **invisible**! On a 32-bit MCU it gives 4, only processing half the data.

**Fix: Always pass the length explicitly:**
```c
uint8_t compute_crc(const uint8_t* data, size_t len) {
    uint8_t crc = 0xFF;
    for (size_t i = 0; i < len; i++) {
        // ...
    }
    return crc;
}

void process_packet(const uint8_t* packet, size_t len) {
    uint8_t crc = compute_crc(packet, len);
}

// Call with:
process_packet(data, sizeof(data));  // sizeof works here, in the declaring scope
```

**The rule:** `sizeof` on an array parameter is ALWAYS a bug. GCC/Clang flag this with `-Wsizeof-array-argument`. Enable it.

**Bonus trap:** `uint8_t data[8]` as a function parameter does NOT create a fixed-size array — it's still just a pointer. The `8` is ignored by the compiler.

questions.starterCode:
#include <cstdio>
#include <cstdint>
#include <cstring>

#define MAX_DEPTH 64
#define MAX_KEY_LEN 32
#define MAX_VAL_LEN 64

typedef struct {
    char key[MAX_KEY_LEN];
    char value[MAX_VAL_LEN];
    int depth;
} config_entry_t;

static int entry_count = 0;
static config_entry_t entries[32];

// Parse a nested config block recursively
void parse_block(const char* input, int* pos, int depth) {
    char key[MAX_KEY_LEN];
    char value[MAX_VAL_LEN];
    char buffer[256];  // scratch buffer for processing

    if (depth > MAX_DEPTH) {
        printf("Max depth exceeded\n");
        return;
    }

    while (input[*pos] != '\0' && input[*pos] != '}') {
        // Skip whitespace
        while (input[*pos] == ' ' || input[*pos] == '\n') (*pos)++;

        if (input[*pos] == '{') {
            (*pos)++;
            parse_block(input, pos, depth + 1);  // RECURSE
            if (input[*pos] == '}') (*pos)++;
            continue;
        }

        // Parse key=value
        int k = 0;
        while (input[*pos] != '=' && input[*pos] != '\0' && k < MAX_KEY_LEN - 1) {
            key[k++] = input[*pos];
            (*pos)++;
        }
        key[k] = '\0';

        if (input[*pos] == '=') (*pos)++;

        int v = 0;
        while (input[*pos] != '\n' && input[*pos] != '\0' && input[*pos] != '}' && v < MAX_VAL_LEN - 1) {
            value[v++] = input[*pos];
            (*pos)++;
        }
        value[v] = '\0';

        // Store entry
        if (entry_count < 32) {
            snprintf(buffer, sizeof(buffer), "[%d] %s = %s", depth, key, value);
            printf("  %s\n", buffer);
            strncpy(entries[entry_count].key, key, MAX_KEY_LEN);
            strncpy(entries[entry_count].value, value, MAX_VAL_LEN);
            entries[entry_count].depth = depth;
            entry_count++;
        }
    }
}

int main() {
    const char* config =
        "name=sensor1\n"
        "rate=100\n"
        "{type=temperature\n"
        " unit=celsius\n"
        " {min=-40\n"
        "  max=125\n"
        " }\n"
        "}\n"
        "enabled=true\n";

    printf("Parsing config:\n");
    int pos = 0;
    parse_block(config, &pos, 0);
    printf("\nParsed %d entries\n", entry_count);

    // Stack usage per call: key(32) + value(64) + buffer(256) + overhead ≈ 400 bytes
    // At MAX_DEPTH=64: 64 × 400 = 25,600 bytes of stack!
    // On a 4KB stack MCU: CRASH at depth ~10

    printf("Done\n");
    return 0;
}

questions.answer:
**Bug: Each recursive call uses ~400 bytes of stack. With MAX_DEPTH=64, worst case is ~25KB — instant death on a 4KB embedded stack.**

Stack per frame:
- `key[32]` = 32 bytes
- `value[64]` = 64 bytes  
- `buffer[256]` = 256 bytes
- Function overhead (return addr, saved regs, pos, depth) ≈ 32 bytes
- **Total: ~384 bytes per recursion level**

At depth 10: 3,840 bytes → 4KB stack is gone.

**Fix 1: Move buffers to static/global (simplest):**
```c
void parse_block(const char* input, int* pos, int depth) {
    static char key[MAX_KEY_LEN];      // shared, not reentrant
    static char value[MAX_VAL_LEN];    // but recursion is sequential
    static char buffer[256];
    // Now each frame is only ~32 bytes
    // ...
```
Caveat: not reentrant/thread-safe.

**Fix 2: Convert to iterative with explicit stack (best):**
```c
typedef struct { int pos; int depth; } parse_state_t;

void parse_config(const char* input) {
    parse_state_t stack[MAX_DEPTH];
    int sp = 0;
    char key[MAX_KEY_LEN], value[MAX_VAL_LEN];
    // One set of buffers, explicit depth tracking
    // ...
}
```

**Fix 3: Reduce MAX_DEPTH + reduce buffer sizes:**
```c
#define MAX_DEPTH 8       // realistic for embedded configs
#define MAX_KEY_LEN 16
#define MAX_VAL_LEN 32
// Stack per frame: ~80 bytes × 8 = 640 bytes ✓
```

**The lesson:** On embedded targets, always calculate worst-case stack depth. Tools like `-fstack-usage` (GCC) report per-function stack frames. Multiply by max recursion depth. If it doesn't fit, refactor to iterative.

