#include <cstdio>
#include <cstdint>
#include <cstring>

// Simulated DMA transfer (in real code: writes to DMA controller registers)
typedef struct {
    uint32_t src_addr;
    uint32_t dst_addr;
    uint32_t count;
    uint32_t config;
} dma_descriptor_t;

// BUG: Struct packing may misalign fields
#pragma pack(push, 1)
typedef struct {
    uint8_t  header;
    uint32_t timestamp;    // offset 1 — misaligned!
    uint16_t sensor_id;
    uint8_t  data[64];
    uint16_t checksum;
} __attribute__((packed)) sensor_packet_t;
#pragma pack(pop)

// DMA buffer — should be cache-line aligned for DMA
static uint8_t dma_buffer[256];

int setup_dma_transfer(sensor_packet_t* packet) {
    printf("Packet address: %p\n", (void*)packet);
    printf("Timestamp field offset: %zu\n",
           (size_t)((uint8_t*)&packet->timestamp - (uint8_t*)packet));
    printf("DMA buffer address: %p\n", (void*)dma_buffer);

    // Check alignment
    if ((uintptr_t)dma_buffer % 4 != 0) {
        printf("WARNING: DMA buffer not 4-byte aligned\n");
    }

    // Copy packet to DMA buffer
    memcpy(dma_buffer, packet, sizeof(sensor_packet_t));

    // Setup DMA descriptor
    dma_descriptor_t desc;
    desc.src_addr = (uint32_t)(uintptr_t)dma_buffer;
    desc.dst_addr = 0x40001000;  // peripheral register
    desc.count = sizeof(sensor_packet_t);
    desc.config = 0x01;  // enable

    printf("DMA transfer: %u bytes from 0x%08X\n", desc.count, desc.src_addr);

    // Simulate reading back the timestamp via DMA buffer pointer
    uint32_t* ts_ptr = (uint32_t*)(dma_buffer + 1);  // offset 1 in buffer
    printf("Timestamp via pointer: %u\n", *ts_ptr);  // POTENTIAL FAULT

    return 0;
}

int main() {
    sensor_packet_t pkt;
    pkt.header = 0xAA;
    pkt.timestamp = 1234567890;
    pkt.sensor_id = 42;
    memset(pkt.data, 0x55, sizeof(pkt.data));
    pkt.checksum = 0xBEEF;

    printf("sizeof(sensor_packet_t) = %zu\n", sizeof(sensor_packet_t));
    printf("Expected without packing: %zu\n", (size_t)76);  // with padding

    setup_dma_transfer(&pkt);

    printf("Done\n");
    return 0;
}

questions.answer:
**Bug 1: Packed struct causes unaligned access to `timestamp`.**

With `__attribute__((packed))`, `timestamp` (a `uint32_t`) sits at offset 1 — not 4-byte aligned. On ARM Cortex-M0/M3, unaligned 32-bit access causes a **HardFault**. On Cortex-M4+, it works but is slower. On x86, it works but with a performance penalty.

The cast `uint32_t* ts_ptr = (uint32_t*)(dma_buffer + 1)` then dereferences a misaligned pointer — undefined behavior.

**Bug 2: DMA buffer is not cache-line aligned.**

`static uint8_t dma_buffer[256]` has no alignment guarantee beyond 1 byte. DMA controllers typically require:
- 4-byte alignment minimum (word-aligned)
- 32-byte alignment for cache coherency (cache line size)

Without proper alignment, DMA can corrupt adjacent data when the cache controller writes back a full cache line.

**Fix:**
```c
// Fix struct: use explicit field access, not packed struct for DMA
typedef struct {
    uint8_t  header;
    uint8_t  _pad[3];        // explicit padding
    uint32_t timestamp;       // now at offset 4 — aligned
    uint16_t sensor_id;
    uint8_t  _pad2[2];
    uint8_t  data[64];
    uint16_t checksum;
    uint8_t  _pad3[2];
} sensor_packet_t;

// If you MUST use packed for wire format, use memcpy to access fields:
uint32_t ts;
memcpy(&ts, &packet->timestamp, sizeof(ts));  // safe unaligned access

// Fix DMA buffer alignment:
static uint8_t dma_buffer[256] __attribute__((aligned(32)));
// or: alignas(32) static uint8_t dma_buffer[256];

// Fix pointer access:
uint32_t ts;
memcpy(&ts, dma_buffer + 1, sizeof(ts));  // memcpy handles alignment
```

**The lesson:** Packed structs and DMA are a dangerous combination. Use `memcpy` for field access in packed/wire-format structs, and always align DMA buffers to the cache line size.

```c
#include <stdint.h>
#include <stdbool.h>
#include <limits.h>

#define MAX_NODES 64
#define INF UINT32_MAX

typedef struct {
    uint8_t  neighbor;
    uint32_t weight;
} edge_t;

typedef struct {
    edge_t edges[MAX_NODES];
    uint8_t edge_count;
} adj_list_t;

void dijkstra(adj_list_t graph[], uint8_t num_nodes, uint8_t src,
              uint32_t dist[], uint8_t prev[]) {
    bool visited[MAX_NODES] = {false};

    for (uint8_t i = 0; i < num_nodes; i++) {
        dist[i] = INF;
        prev[i] = UINT8_MAX;  // undefined
    }
    dist[src] = 0;

    for (uint8_t count = 0; count < num_nodes; count++) {
        // Find unvisited node with min distance (linear scan — 
        // use a min-heap for O((V+E) log V) in production)
        uint32_t min_d = INF;
        uint8_t u = 0;
        for (uint8_t i = 0; i < num_nodes; i++) {
            if (!visited[i] && dist[i] < min_d) {
                min_d = dist[i];
                u = i;
            }
        }
        if (min_d == INF) break;  // remaining nodes unreachable
        visited[u] = true;

        // Relax neighbors
        for (uint8_t j = 0; j < graph[u].edge_count; j++) {
            uint8_t v = graph[u].edges[j].neighbor;
            uint32_t w = graph[u].edges[j].weight;
            if (!visited[v] && dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                prev[v] = u;
            }
        }
    }
}
```

**Key points:**
- O(V²) with linear scan — fine for small embedded graphs (< 64 nodes)
- For larger graphs, swap the linear min-search for a min-heap → O((V+E) log V)
- `prev[]` array lets you reconstruct the actual path
- Watch for integer overflow when adding weights — use `uint32_t` and check before adding
- In firmware contexts: often used for mesh networking (Zigbee, Thread), CAN routing tables, or PCB trace length optimization tools

**Insertion sort is usually the best choice for small embedded sorts:**

```c
void insertion_sort(int16_t arr[], size_t n) {
    for (size_t i = 1; i < n; i++) {
        int16_t key = arr[i];
        size_t j = i;
        while (j > 0 && arr[j - 1] > key) {
            arr[j] = arr[j - 1];
            j--;
        }
        arr[j] = key;
    }
}
```

**Why insertion sort for embedded:**
- **O(1) extra space** — no recursion stack, no auxiliary arrays
- **O(n) best case** — if data is nearly sorted (common with sensor readings that change slowly)
- **Stable sort** — preserves order of equal elements (matters for timestamped data)
- **Small code size** — fits in tight flash budgets
- **Predictable timing** — no worst-case stack overflow risk like quicksort recursion

**Tradeoff comparison:**
| Factor | Insertion | Selection | Quicksort |
|--------|-----------|-----------|----------|
| Average | O(n²) | O(n²) | O(n log n) |
| Nearly sorted | O(n) ✨ | O(n²) | O(n²) worst |
| Stack usage | O(1) | O(1) | O(log n) recursive |
| Stability | Stable | Unstable | Unstable |
| Code size | Tiny | Tiny | Larger |

**Rule of thumb:** For n < 50, insertion sort beats quicksort due to lower overhead. For n > 100, consider an iterative quicksort with explicit stack to avoid recursion.

```c
#include <stdint.h>

// Optimized median of 5 using sorting networks (fewest comparisons)
static inline void sort2(int16_t *a, int16_t *b) {
    if (*a > *b) { int16_t t = *a; *a = *b; *b = t; }
}

int16_t median5(int16_t a, int16_t b, int16_t c, int16_t d, int16_t e) {
    // Sorting network for median of 5: only 6 comparisons needed
    sort2(&a, &b);
    sort2(&c, &d);
    sort2(&a, &c);  // a is now the smallest of {a,b,c,d}
    sort2(&b, &d);  // d is now the largest of {a,b,c,d}
    sort2(&b, &c);  // Now b <= c within the middle group
    sort2(&c, &e);  // Introduce e
    sort2(&b, &c);  // Final: c is the median
    // Actually we need one more pass — proper network:
    // Use the well-known 6-comparison median-of-5:
    sort2(&a, &b); sort2(&c, &d); sort2(&a, &c);
    sort2(&b, &e); sort2(&b, &c); sort2(&c, &e);
    // But cleaner approach:
    return c;
}

// Sliding median filter
typedef struct {
    int16_t buffer[5];
    uint8_t idx;
    uint8_t count;
} median_filter_t;

void median_filter_init(median_filter_t *f) {
    f->idx = 0;
    f->count = 0;
}

int16_t median_filter_update(median_filter_t *f, int16_t sample) {
    f->buffer[f->idx] = sample;
    f->idx = (f->idx + 1) % 5;
    if (f->count < 5) f->count++;

    // Copy and sort (insertion sort on 5 elements)
    int16_t sorted[5];
    for (uint8_t i = 0; i < f->count; i++) sorted[i] = f->buffer[i];
    for (uint8_t i = 1; i < f->count; i++) {
        int16_t key = sorted[i];
        uint8_t j = i;
        while (j > 0 && sorted[j-1] > key) {
            sorted[j] = sorted[j-1];
            j--;
        }
        sorted[j] = key;
    }
    return sorted[f->count / 2];
}
```

**Why median filters matter in firmware:**
- ADC readings often have impulse noise from EMI, power supply ripple, or sensor glitches
- Unlike moving average, median filter completely rejects outliers without smearing edges
- Window of 5 is optimal for most sensor applications — good noise rejection, minimal latency
- O(1) space, O(n log n) per sample — but n=5, so it's effectively constant time

```c
#include <stdint.h>
#include <stdbool.h>

typedef struct {
    uint32_t tokens;          // Current token count (fixed-point: actual = tokens / SCALE)
    uint32_t max_tokens;      // Bucket capacity
    uint32_t refill_rate;     // Tokens added per millisecond
    uint32_t last_refill_ms;  // Timestamp of last refill
} token_bucket_t;

#define TB_SCALE 1000  // Fixed-point scale for sub-integer rates

void token_bucket_init(token_bucket_t *tb, uint32_t max_tokens,
                       uint32_t tokens_per_second, uint32_t now_ms) {
    tb->max_tokens = max_tokens * TB_SCALE;
    tb->tokens = tb->max_tokens;  // Start full
    tb->refill_rate = (tokens_per_second * TB_SCALE) / 1000;  // per ms
    tb->last_refill_ms = now_ms;
}

static void refill(token_bucket_t *tb, uint32_t now_ms) {
    uint32_t elapsed = now_ms - tb->last_refill_ms;  // Handles wrap!
    if (elapsed == 0) return;

    uint32_t new_tokens = elapsed * tb->refill_rate;
    tb->tokens += new_tokens;
    if (tb->tokens > tb->max_tokens)
        tb->tokens = tb->max_tokens;
    tb->last_refill_ms = now_ms;
}

bool token_bucket_consume(token_bucket_t *tb, uint32_t count, uint32_t now_ms) {
    refill(tb, now_ms);
    uint32_t cost = count * TB_SCALE;
    if (tb->tokens >= cost) {
        tb->tokens -= cost;
        return true;   // Allowed
    }
    return false;  // Rate limited
}
```

**Usage example — throttle debug prints to 10/sec:**
```c
token_bucket_t dbg_limiter;
token_bucket_init(&dbg_limiter, 10, 10, get_tick_ms());

void debug_print(const char *msg) {
    if (token_bucket_consume(&dbg_limiter, 1, get_tick_ms())) {
        uart_puts(msg);
    }
    // Silently drop if rate limited
}
```

**Key points:**
- Fixed-point arithmetic avoids floating-point (critical for MCUs without FPU)
- `uint32_t` subtraction handles timer wraparound naturally (unsigned underflow)
- Token bucket allows bursts up to `max_tokens` then throttles to steady rate
- Alternative: leaky bucket (constant output rate, no bursts)

```c
#include <math.h>

typedef struct {
    float x;    // State estimate
    float p;    // Estimate uncertainty (covariance)
    float q;    // Process noise (how much we expect state to drift)
    float r;    // Measurement noise (how noisy the sensor is)
} kalman1d_t;

void kalman_init(kalman1d_t *kf, float initial_estimate,
                 float initial_uncertainty, float process_noise,
                 float measurement_noise) {
    kf->x = initial_estimate;
    kf->p = initial_uncertainty;
    kf->q = process_noise;
    kf->r = measurement_noise;
}

float kalman_update(kalman1d_t *kf, float measurement) {
    // ── Predict step ──
    // x_predicted = x (no control input in simple case)
    // p_predicted = p + q
    kf->p += kf->q;

    // ── Update step ──
    // Kalman gain: how much to trust the measurement vs prediction
    float k = kf->p / (kf->p + kf->r);

    // Update estimate: blend prediction with measurement
    kf->x = kf->x + k * (measurement - kf->x);

    // Update uncertainty
    kf->p = (1.0f - k) * kf->p;

    return kf->x;
}
```

**Usage — smoothing a noisy temperature sensor:**
```c
kalman1d_t temp_filter;
kalman_init(&temp_filter, 
    25.0f,   // Initial guess: 25°C
    1.0f,    // Moderate initial uncertainty
    0.01f,   // Low process noise (temp changes slowly)
    0.5f);   // Moderate sensor noise

void adc_callback(float raw_temp_c) {
    float filtered = kalman_update(&temp_filter, raw_temp_c);
    // filtered is now a smooth, optimal estimate
}
```

**Key insights:**
- **Kalman gain `k`** ranges 0→1: k≈1 means trust measurement, k≈0 means trust prediction
- **Tuning `q` vs `r`**: high q/r ratio → responsive but noisy; low q/r → smooth but laggy
- **No floating point?** Use fixed-point: multiply everything by 2^16 and use int32_t
- **This is the 1D case** — real IMU fusion uses matrix Kalman (6-9 state variables)
- In interviews, showing you understand Kalman filtering signals serious embedded experience

```c
#include <stddef.h>
#include <stdint.h>

// The list node is embedded IN the data structure
typedef struct list_node {
    struct list_node *next;
    struct list_node *prev;
} list_node_t;

// container_of: given a pointer to the embedded node, get the parent struct
#define container_of(ptr, type, member) \
    ((type *)((char *)(ptr) - offsetof(type, member)))

// Initialize a list head (empty = points to itself)
#define LIST_HEAD_INIT(name) { &(name), &(name) }

static inline void list_init(list_node_t *head) {
    head->next = head;
    head->prev = head;
}

static inline void list_add(list_node_t *new_node, list_node_t *head) {
    new_node->next = head->next;
    new_node->prev = head;
    head->next->prev = new_node;
    head->next = new_node;
}

static inline void list_add_tail(list_node_t *new_node, list_node_t *head) {
    new_node->next = head;
    new_node->prev = head->prev;
    head->prev->next = new_node;
    head->prev = new_node;
}

static inline void list_del(list_node_t *entry) {
    entry->prev->next = entry->next;
    entry->next->prev = entry->prev;
    entry->next = NULL;
    entry->prev = NULL;
}

static inline int list_empty(list_node_t *head) {
    return head->next == head;
}

#define list_for_each(pos, head) \
    for (pos = (head)->next; pos != (head); pos = pos->next)

#define list_for_each_entry(pos, head, type, member) \
    for (pos = container_of((head)->next, type, member); \
         &pos->member != (head); \
         pos = container_of(pos->member.next, type, member))
```

**Usage:**
```c
typedef struct {
    uint32_t pid;
    char name[16];
    list_node_t list;  // Embedded!
} task_t;

list_node_t task_list;
list_init(&task_list);

task_t t1 = { .pid = 1, .name = "idle" };
list_add_tail(&t1.list, &task_list);

task_t *t;
list_for_each_entry(t, &task_list, task_t, list) {
    printf("Task %u: %s\n", t->pid, t->name);
}
```

**Why intrusive lists dominate in firmware/kernels:**
1. **No malloc** — the node lives inside the struct, which is often statically allocated
2. **One struct can be on multiple lists** — just embed multiple `list_node_t` members
3. **Zero indirection overhead** — `container_of` is compile-time pointer math, not a dereference
4. **Cache-friendly** — node and data are in the same cache line
5. **Type-generic** — one implementation works for ANY data structure

```c
#include <stdint.h>
#include <stdbool.h>

#define UART_BUF_SIZE 256  // MUST be power of 2
#define UART_BUF_MASK (UART_BUF_SIZE - 1)

_Static_assert((UART_BUF_SIZE & UART_BUF_MASK) == 0,
    "Buffer size must be power of 2");

typedef struct {
    volatile uint32_t head;  // Write index (ISR increments)
    volatile uint32_t tail;  // Read index (main loop increments)
    uint8_t data[UART_BUF_SIZE];
} ring_buf_t;

void ring_init(ring_buf_t *rb) {
    rb->head = 0;
    rb->tail = 0;
}

// Called from ISR — single producer
bool ring_put(ring_buf_t *rb, uint8_t byte) {
    uint32_t next_head = (rb->head + 1) & UART_BUF_MASK;
    if (next_head == rb->tail) return false;  // Full
    rb->data[rb->head] = byte;
    // Compiler barrier — ensure data is written before head advances
    __asm__ volatile("" ::: "memory");
    rb->head = next_head;
    return true;
}

// Called from main loop — single consumer
bool ring_get(ring_buf_t *rb, uint8_t *byte) {
    if (rb->head == rb->tail) return false;  // Empty
    *byte = rb->data[rb->tail];
    __asm__ volatile("" ::: "memory");
    rb->tail = (rb->tail + 1) & UART_BUF_MASK;
    return true;
}

uint32_t ring_count(ring_buf_t *rb) {
    return (rb->head - rb->tail) & UART_BUF_MASK;
}

bool ring_is_empty(ring_buf_t *rb) {
    return rb->head == rb->tail;
}

bool ring_is_full(ring_buf_t *rb) {
    return ((rb->head + 1) & UART_BUF_MASK) == rb->tail;
}
```

**Why this is lock-free and safe:**
1. **Single producer, single consumer** — head is only written by ISR, tail only by main loop
2. **Power-of-2 + bitmask** — `& MASK` is faster than `% SIZE` and avoids division
3. **`volatile` indexes** — compiler won't cache or reorder reads of head/tail
4. **Compiler barrier** — `__asm__ volatile("" ::: "memory")` prevents store reordering
5. **One empty slot sacrifice** — distinguishes full from empty without a separate count variable

**Tradeoff:** Wastes 1 byte of capacity. Alternative: use a separate `volatile bool full` flag, but that adds complexity for SPSC safety.

```c
#include <stdint.h>
#include <stdbool.h>
#include <string.h>

#define TRIE_POOL_SIZE 128  // Max nodes — no malloc
#define ALPHABET_SIZE  37   // a-z, 0-9, underscore

static inline uint8_t char_to_idx(char c) {
    if (c >= 'a' && c <= 'z') return c - 'a';
    if (c >= 'A' && c <= 'Z') return c - 'A';  // Case-insensitive
    if (c >= '0' && c <= '9') return 26 + (c - '0');
    if (c == '_') return 36;
    return 0xFF;  // Invalid
}

typedef struct {
    uint8_t children[ALPHABET_SIZE];  // Index into pool (0 = none)
    bool is_terminal;                 // Marks end of a valid command
    uint8_t cmd_id;                   // Payload: command handler ID
} trie_node_t;

typedef struct {
    trie_node_t pool[TRIE_POOL_SIZE];
    uint8_t pool_used;  // Next free node
} trie_t;

void trie_init(trie_t *t) {
    memset(t, 0, sizeof(*t));
    t->pool_used = 1;  // Node 0 is root
}

bool trie_insert(trie_t *t, const char *word, uint8_t cmd_id) {
    uint8_t node = 0;  // Start at root
    for (; *word; word++) {
        uint8_t idx = char_to_idx(*word);
        if (idx == 0xFF) return false;  // Invalid char
        if (t->pool[node].children[idx] == 0) {
            if (t->pool_used >= TRIE_POOL_SIZE) return false;  // OOM
            t->pool[node].children[idx] = t->pool_used++;
        }
        node = t->pool[node].children[idx];
    }
    t->pool[node].is_terminal = true;
    t->pool[node].cmd_id = cmd_id;
    return true;
}

// Exact match
int16_t trie_search(trie_t *t, const char *word) {
    uint8_t node = 0;
    for (; *word; word++) {
        uint8_t idx = char_to_idx(*word);
        if (idx == 0xFF || t->pool[node].children[idx] == 0)
            return -1;  // Not found
        node = t->pool[node].children[idx];
    }
    return t->pool[node].is_terminal ? t->pool[node].cmd_id : -1;
}

// Autocomplete: find all commands starting with prefix
typedef void (*match_cb)(const char *word, uint8_t cmd_id, void *ctx);

static void collect(trie_t *t, uint8_t node, char *buf, int depth,
                    match_cb cb, void *ctx) {
    if (t->pool[node].is_terminal) {
        buf[depth] = '\0';
        cb(buf, t->pool[node].cmd_id, ctx);
    }
    for (uint8_t i = 0; i < ALPHABET_SIZE; i++) {
        if (t->pool[node].children[i]) {
            buf[depth] = (i < 26) ? ('a' + i) :
                         (i < 36) ? ('0' + i - 26) : '_';
            collect(t, t->pool[node].children[i], buf, depth + 1, cb, ctx);
        }
    }
}

void trie_autocomplete(trie_t *t, const char *prefix,
                       match_cb cb, void *ctx) {
    uint8_t node = 0;
    char buf[64];
    int len = 0;
    for (const char *p = prefix; *p; p++, len++) {
        uint8_t idx = char_to_idx(*p);
        if (idx == 0xFF || t->pool[node].children[idx] == 0) return;
        buf[len] = *p;
        node = t->pool[node].children[idx];
    }
    collect(t, node, buf, len, cb, ctx);
}
```

**Key design decisions:**
- **Static pool allocation** — no malloc, fixed memory footprint, deterministic
- **Case-insensitive** — firmware CLIs are usually case-insensitive
- **Command ID payload** — maps to function pointers or a switch statement
- **Autocomplete with callback** — avoids dynamic array allocation
- **Tradeoff:** Each node is ~38 bytes (37 children + 2 fields). For very sparse command sets, a sorted array with binary search may use less memory

```c
#include <stdint.h>
#include <stdbool.h>

#define MAX_RESOURCES 32  // Up to 32 resources tracked in one uint32_t

typedef struct {
    uint32_t bitmap;      // 1 = free, 0 = allocated
    uint8_t  total;
} bitmap_alloc_t;

void bitmap_init(bitmap_alloc_t *ba, uint8_t count) {
    ba->total = (count > MAX_RESOURCES) ? MAX_RESOURCES : count;
    // Set 'count' LSBs to 1 (all free)
    ba->bitmap = (count >= 32) ? 0xFFFFFFFF : ((1UL << count) - 1);
}

// Allocate: returns resource index (0-based), or -1 if none available
int8_t bitmap_alloc(bitmap_alloc_t *ba) {
    if (ba->bitmap == 0) return -1;  // All allocated

    // Find first set bit — use compiler builtin for hardware CLZ/CTZ
    uint8_t idx = __builtin_ctz(ba->bitmap);  // Count trailing zeros
    ba->bitmap &= ~(1UL << idx);  // Clear bit = mark allocated
    return (int8_t)idx;
}

// Free: return resource to pool
void bitmap_free(bitmap_alloc_t *ba, uint8_t idx) {
    if (idx >= ba->total) return;  // Bounds check
    ba->bitmap |= (1UL << idx);   // Set bit = mark free
}

// Check if a specific resource is allocated
bool bitmap_is_allocated(bitmap_alloc_t *ba, uint8_t idx) {
    return !(ba->bitmap & (1UL << idx));
}

// Count available resources
uint8_t bitmap_available(bitmap_alloc_t *ba) {
    return __builtin_popcount(ba->bitmap);
}

// For > 32 resources, use an array:
typedef struct {
    uint32_t words[4];  // 128 resources
    uint8_t total;
} bitmap_alloc_large_t;

int16_t bitmap_alloc_large(bitmap_alloc_large_t *ba) {
    for (uint8_t w = 0; w < 4; w++) {
        if (ba->words[w] != 0) {
            uint8_t bit = __builtin_ctz(ba->words[w]);
            ba->words[w] &= ~(1UL << bit);
            return (int16_t)(w * 32 + bit);
        }
    }
    return -1;
}
```

**Why bitmaps for resource management:**
- **O(1) alloc/free** — single CTZ instruction + bit clear/set
- **Tiny footprint** — 4 bytes tracks 32 resources
- **No fragmentation** — fixed-size slots, no free-list corruption risk
- **ISR-safe** — can make atomic with compare-and-swap for lock-free allocation
- **Real-world use:** Linux `bitmap_*` API, FreeRTOS event groups, DMA channel allocation, interrupt vector management

**Branch prediction basics:**
Modern processors (including Cortex-M7, A-class ARM) use branch predictors to speculatively execute one path of a conditional. Mispredictions cause pipeline flushes — expensive on deep pipelines.

**Branching version (common pattern):**
```c
int16_t clamp_branching(int16_t val, int16_t min, int16_t max) {
    if (val < min) return min;
    if (val > max) return max;
    return val;
}
```

**Branchless version:**
```c
int16_t clamp_branchless(int16_t val, int16_t min, int16_t max) {
    // Using conditional moves (compiler generates CSEL on ARM)
    val = (val < min) ? min : val;
    val = (val > max) ? max : val;
    return val;
}

// Even more explicit — using arithmetic:
int16_t clamp_arithmetic(int16_t val, int16_t min, int16_t max) {
    int16_t t = val - min;
    t = t & ~(t >> 15);       // if t < 0, t = 0
    t = t + min;
    int16_t u = max - t;
    u = u & ~(u >> 15);       // if u < 0, u = 0  
    return max - u;
}
```

**When branchless helps:**
- Data is **unpredictable** (random sensor values, network packets) — misprediction rate is ~50%
- **Tight inner loops** processing arrays — branch mispredicts stall the pipeline each iteration
- **Security-critical code** — constant-time execution prevents timing side channels
- **DSP/signal processing** — clamp/saturate operations on every sample

**When branchless hurts:**
- Data is **predictable** (almost always in-range) — predictor gets it right 99% of the time
- **Cortex-M0/M3** — no branch predictor, so branchless adds instructions for no benefit
- When branchless requires **more instructions** than the branch — the pipeline flush cost may be less than the extra ALU work

**Key insight for interviews:** "It depends on the microarchitecture." Cortex-M0 has no branch predictor. Cortex-M7 has a basic one. Cortex-A series has sophisticated multi-level predictors. Profile before optimizing.

```c
#include <stdint.h>
#include <stdbool.h>

#define BUFFER_SIZE 256  // Samples per half-buffer

// Double buffer — DMA fills one while CPU processes the other
static volatile int16_t buffer_a[BUFFER_SIZE];
static volatile int16_t buffer_b[BUFFER_SIZE];

typedef struct {
    volatile int16_t *dma_buffer;   // DMA is currently filling this
    volatile int16_t *cpu_buffer;   // CPU is processing this
    volatile bool     data_ready;   // Flag: CPU buffer has new data
    uint32_t          overruns;     // Dropped frames counter
} double_buf_t;

static double_buf_t dbuf;

void dma_adc_init(void) {
    dbuf.dma_buffer = buffer_a;
    dbuf.cpu_buffer = buffer_b;
    dbuf.data_ready = false;
    dbuf.overruns = 0;

    // Configure DMA: ADC → buffer_a, transfer count = BUFFER_SIZE
    // Enable half-transfer and transfer-complete interrupts
    DMA1->CMAR = (uint32_t)buffer_a;
    DMA1->CNDTR = BUFFER_SIZE;
    DMA1->CCR |= DMA_CCR_CIRC | DMA_CCR_TCIE;  // Circular + TC interrupt
}

// DMA Transfer Complete ISR — swap buffers
void DMA1_Channel1_IRQHandler(void) {
    DMA1->IFCR = DMA_IFCR_CTCIF1;  // Clear interrupt flag

    if (dbuf.data_ready) {
        dbuf.overruns++;  // CPU didn't finish in time!
        return;           // Don't swap — let DMA overwrite old data
    }

    // Swap pointers
    volatile int16_t *tmp = dbuf.dma_buffer;
    dbuf.dma_buffer = dbuf.cpu_buffer;
    dbuf.cpu_buffer = tmp;

    // Point DMA at new buffer
    DMA1->CCR &= ~DMA_CCR_EN;
    DMA1->CMAR = (uint32_t)dbuf.dma_buffer;
    DMA1->CNDTR = BUFFER_SIZE;
    DMA1->CCR |= DMA_CCR_EN;

    // Cache maintenance! (Cortex-M7 with D-cache)
    SCB_InvalidateDCache_by_Addr((void*)dbuf.cpu_buffer,
                                 BUFFER_SIZE * sizeof(int16_t));

    dbuf.data_ready = true;
}

// Main loop processing
void process_loop(void) {
    while (1) {
        if (dbuf.data_ready) {
            // Process cpu_buffer — DMA is filling the other one
            int32_t sum = 0;
            for (int i = 0; i < BUFFER_SIZE; i++) {
                sum += dbuf.cpu_buffer[i];
            }
            int16_t average = sum / BUFFER_SIZE;
            // ... do something with average ...

            dbuf.data_ready = false;  // Signal: ready for next swap
        }
        // Can do other work here while waiting
    }
}
```

**Critical synchronization points:**
1. **Cache coherency** — On Cortex-M7, DMA writes bypass D-cache. Must invalidate cache before CPU reads, and clean cache before DMA reads CPU-written data
2. **`volatile` pointers** — Prevent compiler from caching buffer reads across the `data_ready` check
3. **Overrun detection** — If CPU can't keep up, count it rather than corrupting data
4. **Memory alignment** — DMA buffers should be aligned to cache line size (32 bytes on M7) to avoid partial cache line issues
5. **MPU configuration** — Alternatively, mark DMA buffer regions as non-cacheable

**Performance impact:** Double buffering achieves 100% DMA utilization — zero dead time between transfers. Without it, there's a gap while CPU processes the single buffer.

```c
// GCC/Clang built-in: __builtin_expect(expr, expected_value)
#define likely(x)   __builtin_expect(!!(x), 1)
#define unlikely(x) __builtin_expect(!!(x), 0)
```

**What they do:**
1. **Compiler level:** Rearranges generated code so the expected path is the fall-through (no branch taken). The unlikely path is moved to a cold section.
2. **CPU level:** Most branch predictors default to "not taken" for first-encounter branches. Fall-through code also has better instruction cache locality.

**Before (no hints):**
```asm
  cmp   r0, #0
  beq   error_handler    ; Branch to error — 50/50 from CPU's perspective
  ; ... normal path ...
error_handler:
  ; ... error handling ...
```

**After `unlikely(error)`:**
```asm
  cmp   r0, #0
  bne   normal_path      ; Rarely taken (to cold section)
  ; ... normal fast path continues here (fall-through) ...
  b     done
normal_path:              ; This is the hot path — straight line!
  ; ...
```

**Firmware examples where this matters:**

```c
// 1. Error checking in hot ISR path
void uart_rx_isr(void) {
    uint8_t status = UART->SR;
    if (unlikely(status & UART_ERR_MASK)) {
        handle_uart_error(status);  // Rare — framing/overrun errors
        return;
    }
    ring_put(&rx_buf, UART->DR);  // Hot path — normal byte received
}

// 2. Packet parsing — most packets are valid
int parse_packet(const uint8_t *buf, size_t len) {
    if (unlikely(len < MIN_PACKET_SIZE)) return -EINVAL;
    if (unlikely(crc_check(buf, len) != 0)) return -ECRC;
    // Happy path: process valid packet
    process_payload(buf + HEADER_SIZE, len - HEADER_SIZE);
    return 0;
}

// 3. Memory allocation fallback
void *pool_alloc(pool_t *p) {
    void *ptr = pool_try_alloc(p);
    if (unlikely(!ptr)) {
        // Emergency: try compaction, then fail
        pool_compact(p);
        ptr = pool_try_alloc(p);
    }
    return ptr;
}
```

**Measured impact:**
- On Cortex-M7 (6-stage pipeline): 1-3 cycles saved per correct prediction
- In a tight ISR running at 1 MHz: saving 2 cycles × 1M/sec = measurable power/latency improvement
- On Cortex-M0/M3: minimal impact (short pipeline), but code layout still helps I-cache

**Interview tip:** Always mention that these are *hints*, not guarantees. Profile-guided optimization (PGO) with `-fprofile-use` gives the compiler real branch statistics and is even more effective.
